// FetchURLPreview handles the POST /preview request.
// It fetches the URL with a 3-second timeout and extracts the title and meta description.
func FetchURLPreview(ctx echo.Context) error {
	// 1. Bind and validate request
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid request body"})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL field is required"})
	}

	// 2. Setup HTTP Client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// 3. Fetch the URL
	resp, err := client.Get(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "Failed to fetch URL: " + err.Error()})
	}
	defer resp.Body.Close()

	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "Upstream server returned error status"})
	}

	// 4. Parse HTML
	doc, err := html.Parse(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to parse HTML"})
	}

	// 5. Extract Metadata
	title, description := extractMetadata(doc)

	// 6. Return Response
	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// extractMetadata traverses the HTML node tree to find the title and meta description.
func extractMetadata(n *html.Node) (title, description string) {
	var f func(*html.Node)
	f = func(n *html.Node) {
		// Optimization: If we found both, stop traversing (optional, but good for performance)
		if title != "" && description != "" {
			return
		}

		if n.Type == html.ElementNode {
			// Extract Title
			if n.Data == "title" && title == "" {
