// safeDialContext resolves the address and checks if the IP is private/local.
// This prevents SSRF attacks where users input URLs like http://localhost:8080 or http://169.254.169.254.
func safeDialContext(ctx context.Context, network, addr string) (net.Conn, error) {
	host, _, err := net.SplitHostPort(addr)
	if err != nil {
		return nil, err
	}

	ips, err := net.LookupIP(host)
	if err != nil {
		return nil, err
	}

