// PreviewRequest represents the expected JSON input.
type PreviewRequest struct {
	URL string `json:"url"`
}

// PreviewResponse represents the JSON output.
type PreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

func main() {
	// Initialize Echo instance
	e := echo.New()

	// Middleware
	e.Use(middleware.Logger())
	e.Use(middleware.Recover())

	// Routes
	e.POST("/preview", FetchURLPreview)

	// Start server
	e.Logger.Fatal(e.Start(":8080"))
}

// FetchURLPreview handles the POST request to fetch and parse a URL.
// It sets a 3-second timeout for the HTTP client.
func FetchURLPreview(c echo.Context) error {
	// 1. Bind the request body
	req := new(PreviewRequest)
	if err := c.Bind(req); err != nil {
		return c.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid request body"})
	}

	if req.URL == "" {
		return c.JSON(http.StatusBadRequest, map[string]string{"error": "URL field is required"})
	}

	// 2. Setup HTTP Client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// 3. Fetch the URL
	resp, err := client.Get(req.URL)
	if err != nil {
		return c.JSON(http.StatusBadGateway, map[string]string{"error": "Failed to fetch URL: " + err.Error()})
	}
	defer resp.Body.Close()

	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return c.JSON(http.StatusBadGateway, map[string]string{"error": "Upstream server returned non-success status"})
	}

	// 4. Parse HTML
	doc, err := html.Parse(resp.Body)
	if err != nil {
		return c.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to parse HTML content"})
	}

	// 5. Extract Title and Description
	title, description := extractMetadata(doc)

	// 6. Return JSON response
	return c.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// extractMetadata traverses the HTML node tree to find the title and meta description.
func extractMetadata(n *html.Node) (title, description string) {
	var crawler func(*html.Node)

	crawler = func(node *html.Node) {
		// Stop traversing if we found both (optimization)
		if title != "" && description != "" {
			return
		}

		if node.Type == html.ElementNode {
			// Check for <title>
			if node.Data == "title" && title == "" {
				if node.FirstChild != nil && node.FirstChild.Type == html.TextNode {
					title = node.FirstChild.Data
				}
			}

			// Check for <meta name="description" content="...">
			if node.Data == "meta" && description == "" {
				var name, content string
				for _, attr := range node.Attr {
					k := strings.ToLower(attr.Key)
					if k == "name" {
						name = strings.ToLower(attr.Val)
					}
					if k == "content" {
						content = attr.Val
					}
				}
				if name == "description" {
					description = content
				}
			}
		}

		// Traverse children
		for child := node.FirstChild; child != nil; child = child.NextSibling {
			crawler(child)
		}
	}

	crawler(n)
	return title, description
}

