func FetchURLPreview(ctx echo.Context) error {
	reqBody := new(PreviewRequest)
	if err := ctx.Bind(reqBody); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON"})
	}

	// Validate URL
	if reqBody.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL is required"})
	}

	parsedURL, err := url.Parse(reqBody.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL format"})
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Only HTTP/HTTPS URLs are allowed"})
	}

	// Create HTTP Client with timeout
	client := &http.Client{Timeout: 5 * time.Second}

	// Create request with context (propagates cancellation)
	req, err := http.NewRequestWithContext(ctx.Request().Context(), http.MethodGet, parsedURL.String(), nil)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to create request"})
	}

	// Set User-Agent to avoid being blocked by some servers
	req.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	resp, err := client.Do(req)
	if err != nil {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": fmt.Sprintf("Remote server returned HTTP %d", resp.StatusCode)})
	}

	// Security: Limit the amount of data read to 5MB to prevent memory exhaustion
	limitReader := io.LimitReader(resp.Body, 5*1024*1024)

	// Parse HTML
	title, description, err := extractTitleAndDescription(limitReader)
	if err != nil {
		// Even if parsing fails, we might return partial data or a specific error.
		// Here we just log it internally (omitted) and return empty strings.
	}

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// extractTitleAndDescription parses the HTML stream and finds metadata.
func extractTitleAndDescription(r io.Reader) (string, string, error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	var title, description string
	var f func(*html.Node)

	// Recursive function to traverse the DOM
	f = func(n *html.Node) {
		// Optimization: If we found both, stop traversing (not strictly implemented here for simplicity, 
		// but in a large DOM you might want to return early).

		if n.Type == html.ElementNode {
			// Extract Title
			if n.Data == "title" && title == "" {
				if n.FirstChild != nil {
					title = n.FirstChild.Data
				}
			}

			// Extract Meta Description
			if n.Data == "meta" && description == "" {
				var name, content string
				for _, a := range n.Attr {
					if a.Key == "name" {
						name = a.Val
					}
					if a.Key == "content" {
						content = a.Val
					}
				}
				// Case-insensitive check for "description"
				if strings.EqualFold(name, "description") {
					description = content
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}

	f(doc)
	return strings.TrimSpace(title), strings.TrimSpace(description), nil
}

