// Private IP blocks to block for SSRF protection
var privateIPBlocks []*net.IPNet

func init() {
	for _, cidr := range []string{
		"127.0.0.0/8",    // IPv4 loopback
		"10.0.0.0/8",     // RFC1918
		"172.16.0.0/12",  // RFC1918
		"192.168.0.0/16", // RFC1918
		"169.254.0.0/16", // Link-local
		"::1/128",        // IPv6 loopback
		"fe80::/10",      // IPv6 link-local
		"fc00::/7",       // IPv6 unique local
	} {
		_, block, err := net.ParseCIDR(cidr)
		if err == nil {
			privateIPBlocks = append(privateIPBlocks, block)
		}
	}
}

// isPrivateIP checks if an IP belongs to private/local networks
func isPrivateIP(ip net.IP) bool {
	if ip.IsLoopback() || ip.IsUnspecified() {
		return true
	}
	for _, block := range privateIPBlocks {
		if block.Contains(ip) {
			return true
		}
	}
	return false
}

// safeTransport returns a Transport that blocks connections to private IPs
func safeTransport() *http.Transport {
	return &http.Transport{
		DialContext: (&net.Dialer{
			Timeout:   5 * time.Second,
			KeepAlive: 30 * time.Second,
			// Control hook is called after DNS resolution but before connection.
			// This prevents DNS rebinding and ensures we don't connect to internal IPs.
			Control: func(network, address string, c syscall.RawConn) error {
				host, _, err := net.SplitHostPort(address)
				if err != nil {
					return err
				}
				ip := net.ParseIP(host)
				if ip == nil {
					return errors.New("invalid IP address")
				}
				if isPrivateIP(ip) {
					return fmt.Errorf("access to private IP %s is forbidden", ip)
				}
				return nil
			},
		}).DialContext,
		ForceAttemptHTTP2:     true,
		MaxIdleConns:          100,
		IdleConnTimeout:       90 * time.Second,
		TLSHandshakeTimeout:   10 * time.Second,
		ExpectContinueTimeout: 1 * time.Second,
	}
}

func FetchURLPreview(ctx echo.Context) error {
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON"})
	}

	// 1. Validate URL format
	parsedURL, err := url.Parse(req.URL)
	if err != nil || parsedURL.Host == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL format"})
	}

	// 2. Restrict Scheme
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Only HTTP/HTTPS URLs are allowed"})
	}

	// 3. Setup Safe Client (SSRF & Timeouts)
	client := &http.Client{
		Timeout:   10 * time.Second, // Total timeout for the request
		Transport: safeTransport(),
		// Prevent infinite redirects
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			if len(via) >= 10 {
				return errors.New("stopped after 10 redirects")
			}
			return nil
		},
	}

	// Create a request with context
	httpReq, err := http.NewRequestWithContext(ctx.Request().Context(), http.MethodGet, parsedURL.String(), nil)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to create request"})
	}
	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	resp, err := client.Do(httpReq)
	if err != nil {
		// Log the specific error internally in a real app
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": fmt.Sprintf("Remote server returned HTTP %d", resp.StatusCode)})
	}

	// 4. Validate Content-Type (Only parse HTML)
	contentType := resp.Header.Get("Content-Type")
	if !strings.Contains(strings.ToLower(contentType), "text/html") {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL does not point to an HTML document"})
	}

	// 5. Limit Response Size (DoS Protection)
	// Read max 1MB to prevent memory exhaustion
	limitReader := io.LimitReader(resp.Body, 1024*1024)

	// 6. Parse HTML
	title, description := extractTitleAndDescription(limitReader)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// extractTitleAndDescription parses HTML stream to find title and meta description
func extractTitleAndDescription(r io.Reader) (string, string) {
	z := html.NewTokenizer(r)
	var title, description string
	var inTitle bool

	// Loop through HTML tokens
	for {
		tt := z.Next()
		switch tt {
		case html.ErrorToken:
			// End of file or error
			return title, description
		case html.StartTagToken, html.SelfClosingTagToken:
			t := z.Token()
			if t.Data == "title" {
				inTitle = true
			} else if t.Data == "meta" {
				var name, content string
				for _, a := range t.Attr {
					if a.Key == "name" {
						name = a.Val
					} else if a.Key == "content" {
						content = a.Val
					}
				}
				if strings.EqualFold(name, "description") {
					description = content
				}
			}
		case html.TextToken:
			if inTitle {
				title = string(z.Text())
				inTitle = false
			}
		case html.EndTagToken:
			t := z.Token()
			if t.Data == "title" {
				inTitle = false
			}
		}
	}
}

