		})
	}

	// 6. Extract Metadata
	title, description := extractMetadata(doc)

	// 7. Return Response
	return c.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// extractMetadata traverses the HTML node tree to find the title and meta description.
func extractMetadata(n *html.Node) (title, description string) {
	var crawler func(*html.Node)
	crawler = func(node *html.Node) {
		if node.Type == html.ElementNode {
			// Check for <title>
			if node.Data == "title" && title == "" {
				if node.FirstChild != nil {
					title = node.FirstChild.Data
				}
			}

			// Check for <meta name="description" content="...">
			if node.Data == "meta" && description == "" {
				var name, content string
				for _, attr := range node.Attr {
					k := strings.ToLower(attr.Key)
					if k == "name" {
						name = strings.ToLower(attr.Val)
					}
					if k == "content" {
						content = attr.Val
					}
				}
				if name == "description" {
					description = content
				}
			}
		}

		// Traverse children
		for c := node.FirstChild; c != nil; c = c.NextSibling {
			crawler(c)
		}
	}

	crawler(n)
	return title, description
}

