	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": fmt.Sprintf("Remote server returned HTTP %d", resp.StatusCode)})
	}

	// 6. DoS Protection: Limit the amount of data read (e.g., 1MB)
	// We only need the head of the HTML for title/description usually.
	limitReader := io.LimitReader(resp.Body, 1024*1024) // 1 MB limit

