package main

import (
	"net/http"
	"strings"
	"time"

	"github.com/labstack/echo/v4"
	"golang.org/x/net/html"
)

// PreviewRequest defines the expected JSON body for the request.
type PreviewRequest struct {
	URL string `json:"url"`
}

// PreviewResponse defines the JSON response structure.
type PreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

func main() {
	e := echo.New()

	// Register the handler
	e.POST("/preview", FetchURLPreview)

	// Start the server
	e.Logger.Fatal(e.Start(":8080"))
}

// FetchURLPreview handles the POST request to fetch and parse URL metadata.
func FetchURLPreview(c echo.Context) error {
	// Bind request body
	reqBody := new(PreviewRequest)
	if err := c.Bind(reqBody); err != nil {
		return c.JSON(http.StatusBadRequest, map[string]string{
			"error": "Invalid request body",
		})
	}

	if reqBody.URL == "" {
		return c.JSON(http.StatusBadRequest, map[string]string{
			"error": "URL field is required",
		})
	}

	// Create HTTP client with the required 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Fetch the URL
	resp, err := client.Get(reqBody.URL)
	if err != nil {
		return c.JSON(http.StatusBadGateway, map[string]string{
			"error": "Failed to fetch URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	if resp.StatusCode >= 400 {
		return c.JSON(http.StatusBadGateway, map[string]string{
			"error": "Remote server returned an error status",
		})
	}

	// Parse HTML content
	doc, err := html.Parse(resp.Body)
	if err != nil {
		return c.JSON(http.StatusInternalServerError, map[string]string{
			"error": "Failed to parse HTML content",
		})
	}

	// Extract metadata
	title, description := extractMetadata(doc)

	// Return JSON response
	return c.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// extractMetadata traverses the HTML node tree to find the title and meta description.
func extractMetadata(n *html.Node) (string, string) {
	var title, description string
	var crawler func(*html.Node)

	crawler = func(node *html.Node) {
		// Stop traversing if we found both (optimization)
		if title != "" && description != "" {
			return
		}

		if node.Type == html.ElementNode {
			// Extract Title
			if node.Data == "title" && title == "" {
				if node.FirstChild != nil {
					title = node.FirstChild.Data
				}
			}

			// Extract Meta Description
			if node.Data == "meta" && description == "" {
				var name, content string
				for _, attr := range node.Attr {
					k := strings.ToLower(attr.Key)
					if k == "name" {
						name = strings.ToLower(attr.Val)
					}
					if k == "content" {
						content = attr.Val
					}
				}
				if name == "description" {
					description = content
				}
			}
		}

		// Recursively traverse children
		for c := node.FirstChild; c != nil; c = c.NextSibling {
			crawler(c)
		}
	}

	crawler(n)
	return title, description
}

