// FetchURLPreview handles the request to fetch and parse a URL.
func FetchURLPreview(c echo.Context) error {
	// 1. Bind the request body
	req := new(PreviewRequest)
	if err := c.Bind(req); err != nil {
		return c.JSON(http.StatusBadRequest, map[string]string{
			"error": "Invalid request body",
		})
	}

	if req.URL == "" {
		return c.JSON(http.StatusBadRequest, map[string]string{
			"error": "URL field is required",
		})
	}

	// 2. Create an HTTP client with the required 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Create a request with context (good practice)
	// We use the client's timeout, but we can also derive context from the incoming request
	httpReq, err := http.NewRequestWithContext(c.Request().Context(), http.MethodGet, req.URL, nil)
	if err != nil {
		return c.JSON(http.StatusInternalServerError, map[string]string{
			"error": "Failed to create request",
		})
	}

	// Set a User-Agent to avoid being blocked by some servers
	httpReq.Header.Set("User-Agent", "Go-URL-Previewer/1.0")

	// 3. Fetch the content
	resp, err := client.Do(httpReq)
	if err != nil {
		// Distinguish between timeout and other errors
		if strings.Contains(err.Error(), "Client.Timeout") || strings.Contains(err.Error(), "context deadline exceeded") {
			return c.JSON(http.StatusGatewayTimeout, map[string]string{
				"error": "Request timed out after 3 seconds",
			})
		}
		return c.JSON(http.StatusBadGateway, map[string]string{
			"error": "Failed to fetch URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

