			"error": "Upstream server returned non-200 status",
		})
	}

	// 4. Parse the HTML
	title, description, err := parseHTMLContent(resp.Body)
	if err != nil {
		return c.JSON(http.StatusInternalServerError, map[string]string{
			"error": "Failed to parse HTML content",
		})
	}

	// 5. Return the result
	return c.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// parseHTMLContent helper function to extract title and meta description using golang.org/x/net/html
func parseHTMLContent(r io.Reader) (string, string, error) {
    doc, err := html.Parse(r) // r is resp.Body
	if err != nil {
		return "", "", err
	}

	var title, description string
	var f func(*html.Node)

	f = func(n *html.Node) {
		// If we found both, we can stop (optimization optional, here we traverse full tree for simplicity)
		if n.Type == html.ElementNode {
			// Check for <title>
			if n.Data == "title" && title == "" {
				if n.FirstChild != nil {
					title = n.FirstChild.Data
				}
			}

			// Check for <meta name="description" content="...">
			if n.Data == "meta" && description == "" {
				var name, content string
				for _, a := range n.Attr {
					k := strings.ToLower(a.Key)
					if k == "name" {
						name = strings.ToLower(a.Val)
					} else if k == "content" {
						content = a.Val
					}
				}
				if name == "description" {
					description = content
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}

	f(doc)

	return strings.TrimSpace(title), strings.TrimSpace(description), nil
}

