// FetchURLPreview handles the URL preview generation.
// It fetches the URL with a 3-second timeout and extracts the title and meta description.
func FetchURLPreview(c echo.Context) error {
	// 1. Bind and validate the request
	req := new(PreviewRequest)
	if err := c.Bind(req); err != nil {
		return c.JSON(http.StatusBadRequest, map[string]string{
			"error": "Invalid request body",
		})
	}

	if req.URL == "" {
		return c.JSON(http.StatusBadRequest, map[string]string{
			"error": "URL field is required",
		})
	}

	// 2. Setup Context with 3-second timeout
	// We use context.Background() as base to ensure we get the full 3 seconds
	// independent of the incoming request context, though inheriting c.Request().Context() is also valid.
	ctx, cancel := context.WithTimeout(context.Background(), 3*time.Second)
	defer cancel()

	// 3. Create the HTTP Request
	httpReq, err := http.NewRequestWithContext(ctx, http.MethodGet, req.URL, nil)
	if err != nil {
		return c.JSON(http.StatusInternalServerError, map[string]string{
			"error": "Failed to create HTTP request",
		})
	}

	// Set a user agent to avoid being blocked by some servers
	httpReq.Header.Set("User-Agent", "URLPreviewBot/1.0")

	// 4. Execute the Request
	client := &http.Client{}
	resp, err := client.Do(httpReq)
	if err != nil {
		// Check specifically for timeout
		if ctx.Err() == context.DeadlineExceeded {
			return c.JSON(http.StatusGatewayTimeout, map[string]string{
				"error": "Request timed out after 3 seconds",
			})
		}
		return c.JSON(http.StatusBadGateway, map[string]string{
			"error": "Failed to fetch URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return c.JSON(http.StatusBadGateway, map[string]string{
			"error": "Upstream server returned error status",
		})
	}

	// 5. Parse HTML
	doc, err := html.Parse(resp.Body)
	if err != nil {
		return c.JSON(http.StatusInternalServerError, map[string]string{
			"error": "Failed to parse HTML content",
		})
	}

	// 6. Extract Metadata
	title, description := extractMetadata(doc)

	// 7. Return JSON response
	return c.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// extractMetadata traverses the HTML node tree to find the <title> tag
// and the <meta name="description"> tag.
func extractMetadata(n *html.Node) (title, description string) {
	var crawler func(*html.Node)
	crawler = func(node *html.Node) {
		// Extract Title
		if node.Type == html.ElementNode && node.Data == "title" {
			if node.FirstChild != nil {
				title = node.FirstChild.Data
			}
		}

		// Extract Meta Description
		if node.Type == html.ElementNode && node.Data == "meta" {
			var name, content string
			for _, attr := range node.Attr {
				if attr.Key == "name" {
					name = attr.Val
				}
				if attr.Key == "content" {
					content = attr.Val
				}
			}
			if name == "description" {
				description = content
			}
		}

		// Continue traversal
		for c := node.FirstChild; c != nil; c = c.NextSibling {
			crawler(c)
		}
	}

	crawler(n)
	return
}

