// isPrivateIP checks if an IP belongs to private/local networks (SSRF protection)
func isPrivateIP(ip net.IP) bool {
	if ip.IsLoopback() || ip.IsLinkLocalMulticast() || ip.IsLinkLocalUnicast() {
		return true
	}
	// Check IPv4 private ranges (RFC 1918) and others
	if ip4 := ip.To4(); ip4 != nil {
		switch {
		case ip4[0] == 10:
