				var content string
				for _, a := range t.Attr {
					if a.Key == "name" && strings.EqualFold(a.Val, "description") {
						isDesc = true
					}
					if a.Key == "content" {
						content = a.Val
					}
				}
				if isDesc && content != "" {
					description = content
				}
			}
		}

