package main

import (
	"io"
	"net/http"
	"strings"
	"time"

	"github.com/labstack/echo/v4"
	"golang.org/x/net/html"
)

// PreviewRequest defines the expected JSON body for the request.
type PreviewRequest struct {
	URL string `json:"url"`
}

// PreviewResponse defines the JSON response structure.
type PreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

// FetchURLPreview handles the POST request to fetch and parse URL metadata.
func FetchURLPreview(ctx echo.Context) error {
	// Bind the request body
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{
			"error": "Invalid request body",
		})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{
			"error": "URL field is required",
		})
	}

	// Create HTTP client with 3-second timeout requirement
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Fetch the URL
	resp, err := client.Get(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadGateway, map[string]string{
			"error": "Failed to fetch URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Parse HTML content
	title, description, err := extractMeta(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{
			"error": "Failed to parse HTML content",
		})
	}

	// Return result
	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// extractMeta parses the HTML body to find the <title> tag and <meta name="description">.
func extractMeta(body io.Reader) (title string, description string, err error) {
	doc, err := html.Parse(body)
	if err != nil {
		return "", "", err
	}

	var crawler func(*html.Node)
	crawler = func(n *html.Node) {
		// Check for <title>
		if n.Type == html.ElementNode && n.Data == "title" {
			if n.FirstChild != nil {
				title = n.FirstChild.Data
			}
		}

		// Check for <meta name="description" content="...">
		if n.Type == html.ElementNode && n.Data == "meta" {
			var name, content string
			for _, attr := range n.Attr {
				if attr.Key == "name" {
					name = attr.Val
				}
				if attr.Key == "content" {
					content = attr.Val
				}
			}
			if strings.EqualFold(name, "description") {
				description = content
			}
		}

		// Traverse children
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			crawler(c)
		}
	}

	crawler(doc)
	return title, description, nil
}

func main() {
	// Initialize Echo instance
	e := echo.New()

	// Register the handler
	e.POST("/preview", FetchURLPreview)

	// Start server
	e.Logger.Fatal(e.Start(":8080"))
}

