// PreviewRequest represents the incoming JSON payload.
type PreviewRequest struct {
	URL string `json:"url"`
}

// PreviewResponse represents the outgoing JSON payload.
type PreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

