func FetchURLPreview(ctx echo.Context) error {
	// 1. Bind the request body
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid request body"})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL is required"})
	}

	// 2. Setup HTTP Client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// 3. Fetch the URL
	resp, err := client.Get(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "Failed to fetch URL: " + err.Error()})
	}
	defer resp.Body.Close()

	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "Remote server returned non-success status"})
	}

	// 4. Parse the HTML content
	doc, err := html.Parse(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to parse HTML"})
	}

	// 5. Extract Title and Meta Description
	title, description := extractMetadata(doc)

	// 6. Return the result
	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// extractMetadata traverses the HTML node tree to find the title and meta description.
func extractMetadata(n *html.Node) (title, description string) {
	var crawler func(*html.Node)
	crawler = func(node *html.Node) {
		// Stop traversing if we found both (optimization optional, but good practice)
		if title != "" && description != "" {
			return
		}

		if node.Type == html.ElementNode {
			// Extract Title
			if node.Data == "title" && title == "" {
				if node.FirstChild != nil {
					title = node.FirstChild.Data
				}
			}

			// Extract Meta Description
			if node.Data == "meta" && description == "" {
				var name, content string
				for _, attr := range node.Attr {
					if attr.Key == "name" {
						name = attr.Val
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}
				if strings.EqualFold(name, "description") {
					description = content
				}
			}
		}

		for c := node.FirstChild; c != nil; c = c.NextSibling {
			crawler(c)
		}
	}

	crawler(n)
	return title, description
}

