func FetchURLPreview(c echo.Context) error {
	reqBody := new(PreviewRequest)
	if err := c.Bind(reqBody); err != nil {
		return c.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON"})
	}

	// Validate URL
	parsedURL, err := url.Parse(reqBody.URL)
	if err != nil || reqBody.URL == "" {
		return c.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL format"})
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return c.JSON(http.StatusBadRequest, map[string]string{"error": "Only HTTP/HTTPS URLs are allowed"})
	}

	// Create context with timeout
	ctx, cancel := context.WithTimeout(c.Request().Context(), 5*time.Second)
	defer cancel()

	// Prepare Request
	httpReq, err := http.NewRequestWithContext(ctx, http.MethodGet, parsedURL.String(), nil)
	if err != nil {
		return c.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to create request"})
	}
	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	// Fetch
	client := &http.Client{}
	resp, err := client.Do(httpReq)
	if err != nil {
		return c.JSON(http.StatusBadGateway, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return c.JSON(http.StatusBadGateway, map[string]string{"error": fmt.Sprintf("Remote server returned HTTP %d", resp.StatusCode)})
	}

	// Limit reader to prevent memory exhaustion (5MB limit)
	limitReader := io.LimitReader(resp.Body, 5*1024*1024)

	// Parse
	title, description := extractTitleAndDescription(limitReader)

	return c.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

func extractTitleAndDescription(r io.Reader) (string, string) {
	z := html.NewTokenizer(r)
	var title, description string
	var inTitle bool

	for {
		tt := z.Next()
		switch tt {
		case html.ErrorToken:
			return title, description
		case html.StartTagToken, html.SelfClosingTagToken:
			t := z.Token()

			// Only consider <title> if it's a start tag, not self-closing
			if t.Data == "title" && tt == html.StartTagToken {
				inTitle = true
			} else if t.Data == "meta" {
				var name, content string
				for _, attr := range t.Attr {
					k := strings.ToLower(attr.Key)
					if k == "name" {
						name = attr.Val
					} else if k == "content" {
						content = attr.Val
					}
				}
				if strings.EqualFold(name, "description") {
					description = content
				}
			}
		case html.TextToken:
			if inTitle {
				title = z.Token().Data
