package main

import (
	"context"
	"net/http"
	"strings"
	"time"

	"github.com/labstack/echo/v4"
	"golang.org/x/net/html"
)

// PreviewRequest represents the incoming JSON payload
type PreviewRequest struct {
	URL string `json:"url"`
}

// PreviewResponse represents the outgoing JSON payload
type PreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

func main() {
	e := echo.New()

	// Register the handler under the /preview path
	e.POST("/preview", FetchURLPreview)

	// Start the server
	e.Logger.Fatal(e.Start(":8080"))
}

// FetchURLPreview handles the request to fetch and parse a URL
func FetchURLPreview(c echo.Context) error {
	// 1. Bind the request body
	req := new(PreviewRequest)
	if err := c.Bind(req); err != nil {
		return c.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid request body"})
	}

	if req.URL == "" {
		return c.JSON(http.StatusBadRequest, map[string]string{"error": "URL field is required"})
	}

	// 2. Setup HTTP Client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Create a request with context (good practice, though client timeout handles the hard limit)
	ctx, cancel := context.WithTimeout(c.Request().Context(), 3*time.Second)
	defer cancel()

	httpReq, err := http.NewRequestWithContext(ctx, http.MethodGet, req.URL, nil)
	if err != nil {
		return c.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL format"})
	}

	// Set a User-Agent to avoid being blocked by some servers
	httpReq.Header.Set("User-Agent", "Go-URL-Previewer/1.0")

	// 3. Fetch the content
	resp, err := client.Do(httpReq)
	if err != nil {
		return c.JSON(http.StatusBadGateway, map[string]string{"error": "Failed to fetch URL: " + err.Error()})
	}
	defer resp.Body.Close()

	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return c.JSON(http.StatusBadGateway, map[string]string{"error": "Remote server returned non-success status"})
	}

	// 4. Parse HTML
	doc, err := html.Parse(resp.Body)
	if err != nil {
		return c.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to parse HTML"})
	}

	title, description := extractMetadata(doc)

	// 5. Return JSON response
	return c.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// extractMetadata traverses the HTML node tree to find the title and meta description
func extractMetadata(n *html.Node) (title string, description string) {
	var crawler func(*html.Node)
	crawler = func(node *html.Node) {
		// Stop if we found both (optimization)
		if title != "" && description != "" {
			return
		}

		if node.Type == html.ElementNode {
			// Extract Title
			if node.Data == "title" && title == "" {
				if node.FirstChild != nil {
					title = node.FirstChild.Data
				}
			}

			// Extract Meta Description
			if node.Data == "meta" && description == "" {
				var name, content string
				for _, attr := range node.Attr {
					if attr.Key == "name" {
						name = strings.ToLower(attr.Val)
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}
				if name == "description" {
					description = content
				}
			}
		}

		for child := node.FirstChild; child != nil; child = child.NextSibling {
			crawler(child)
		}
	}

	crawler(n)
	return title, description
}

