// FetchURLPreview handles the POST request to fetch and parse URL metadata
func FetchURLPreview(c echo.Context) error {
	// 1. Bind incoming JSON body
	req := new(PreviewRequest)
	if err := c.Bind(req); err != nil {
		return c.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid request body"})
	}

	if req.URL == "" {
		return c.JSON(http.StatusBadRequest, map[string]string{"error": "URL field is required"})
	}

	// 2. Create a context with a 3-second timeout
	ctx, cancel := context.WithTimeout(c.Request().Context(), 3*time.Second)
	defer cancel()

	// 3. Create the HTTP request
	httpReq, err := http.NewRequestWithContext(ctx, http.MethodGet, req.URL, nil)
	if err != nil {
		return c.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to create request"})
	}

	// Set a User-Agent to avoid being blocked by some servers
	httpReq.Header.Set("User-Agent", "Go-URL-Previewer/1.0")

	// 4. Execute the request
	client := &http.Client{}
	resp, err := client.Do(httpReq)
	if err != nil {
		// Check if error was due to timeout
		if ctx.Err() == context.DeadlineExceeded {
			return c.JSON(http.StatusGatewayTimeout, map[string]string{"error": "Request timed out after 3 seconds"})
		}
		return c.JSON(http.StatusBadGateway, map[string]string{"error": "Failed to fetch URL: " + err.Error()})
	}
	defer resp.Body.Close()

	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return c.JSON(http.StatusBadGateway, map[string]string{"error": "Upstream server returned non-success status"})
	}

	// 5. Parse HTML content
	doc, err := html.Parse(resp.Body)
	if err != nil {
		return c.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to parse HTML content"})
	}

	// 6. Extract Title and Description
	title, description := extractMetadata(doc)

	// 7. Return Result
	return c.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// extractMetadata traverses the HTML node tree to find the title and meta description
func extractMetadata(n *html.Node) (title, description string) {
	var f func(*html.Node)
	f = func(n *html.Node) {
		// Check for <title> tag
		if n.Type == html.ElementNode && n.Data == "title" {
			if n.FirstChild != nil {
				title = n.FirstChild.Data
			}
		}

		// Check for <meta> tag with name="description"
		if n.Type == html.ElementNode && n.Data == "meta" {
			var name, content string
			for _, a := range n.Attr {
				if a.Key == "name" {
					name = a.Val
				}
				if a.Key == "content" {
					content = a.Val
				}
			}
			// Use EqualFold for case-insensitive comparison (e.g., "Description")
			if strings.EqualFold(name, "description") {
				description = content
			}
		}

		// Recursively traverse children
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}
	f(n)
	return
}

