	e.Logger.Fatal(e.Start(":8080"))
}

func FetchURLPreview(ctx echo.Context) error {
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON"})
	}

	// Validate URL
	parsedURL, err := url.Parse(req.URL)
	if err != nil || req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL format"})
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Only HTTP/HTTPS URLs are allowed"})
	}

	// Create HTTP Client with timeout
	client := &http.Client{Timeout: 5 * time.Second}

	// Create a new HTTP request
	httpReq, err := http.NewRequest(http.MethodGet, parsedURL.String(), nil)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to create request"})
	}
	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	// Fetch the URL
	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": fmt.Sprintf("Remote server returned HTTP %d", resp.StatusCode)})
	}

	// Basic check to ensure we are parsing HTML
	contentType := resp.Header.Get("Content-Type")
	if !strings.Contains(strings.ToLower(contentType), "text/html") {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL does not point to an HTML page"})
	}

	// Limit reader to prevent memory exhaustion on huge pages (e.g., 5MB limit)
	limitedReader := io.LimitReader(resp.Body, 5*1024*1024)
	body, err := io.ReadAll(limitedReader)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response body"})
	}

	title, description := extractTitleAndDescription(body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// extractTitleAndDescription parses HTML bytes to find the title tag and meta description
func extractTitleAndDescription(htmlContent []byte) (string, string) {
	z := html.NewTokenizer(bytes.NewReader(htmlContent))

	var title, description string
	var inTitle bool

	for {
		tt := z.Next()

		if tt == html.ErrorToken {
			break
		}

		token := z.Token()

		switch tt {
		case html.StartTagToken, html.SelfClosingTagToken:
			// Check for <title>
			if token.Data == "title" {
				inTitle = true
			}

			// Check for <meta name="description" content="...">
			if token.Data == "meta" {
				var name, content string
				for _, attr := range token.Attr {
					if attr.Key == "name" {
						name = attr.Val
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}
				if strings.EqualFold(name, "description") {
					description = content
				}
			}

		case html.TextToken:
			if inTitle {
				title = token.Data
				inTitle = false // We only want the first text node inside title
			}

		case html.EndTagToken:
			if token.Data == "title" {
				inTitle = false
			}
		}

		// Optimization: If we found both, we can stop parsing
		if title != "" && description != "" {
			break
		}
	}

	return title, description
}

