// PreviewRequest defines the expected JSON body for the request.
type PreviewRequest struct {
	URL string `json:"url"`
}

// PreviewResponse defines the JSON response structure.
type PreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

func main() {
	e := echo.New()

	// Register the handler under the /preview path
	e.POST("/preview", FetchURLPreview)

	// Start the server
	e.Logger.Fatal(e.Start(":8080"))
}

// FetchURLPreview handles the request to fetch and parse a URL.
func FetchURLPreview(c echo.Context) error {
	// 1. Bind the request body
	req := new(PreviewRequest)
	if err := c.Bind(req); err != nil {
		return c.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid request body"})
	}

	if req.URL == "" {
		return c.JSON(http.StatusBadRequest, map[string]string{"error": "URL field is required"})
	}

	// 2. Create HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// 3. Fetch the URL
	resp, err := client.Get(req.URL)
	if err != nil {
		return c.JSON(http.StatusBadGateway, map[string]string{"error": "Failed to fetch URL: " + err.Error()})
	}
	defer resp.Body.Close()

	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return c.JSON(http.StatusBadGateway, map[string]string{"error": "URL returned non-success status code"})
	}

	// 4. Parse the HTML content
	doc, err := html.Parse(resp.Body)
	if err != nil {
		return c.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to parse HTML content"})
	}

	// 5. Extract Title and Description
	title, description := extractMetadata(doc)

	// 6. Return the result
	return c.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// extractMetadata traverses the HTML node tree to find the title and meta description.
func extractMetadata(n *html.Node) (title string, description string) {
	var crawler func(*html.Node)
	crawler = func(node *html.Node) {
		if node.Type == html.ElementNode {
			// Check for <title>
			if node.Data == "title" && node.FirstChild != nil {
				title = node.FirstChild.Data
			}

			// Check for <meta name="description" content="...">
			if node.Data == "meta" {
				var name, content string
				for _, attr := range node.Attr {
					if attr.Key == "name" {
						name = strings.ToLower(attr.Val)
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}
				if name == "description" {
					description = content
				}
			}
		}

		// Continue traversing
		for child := node.FirstChild; child != nil; child = child.NextSibling {
			crawler(child)
		}
	}

	crawler(n)
	return title, description
}

