	e.Logger.Fatal(e.Start(":8080"))
}

// FetchURLPreview handles the POST request to fetch and parse URL metadata.
func FetchURLPreview(c echo.Context) error {
	// 1. Bind and Validate Input
	req := new(PreviewRequest)
	if err := c.Bind(req); err != nil {
		return c.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid request body"})
	}

	if req.URL == "" {
		return c.JSON(http.StatusBadRequest, map[string]string{"error": "URL field is required"})
	}

	// 2. Create HTTP Client with 3-second timeout
	// We use a custom client with a timeout to satisfy the requirement.
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Create a request with context (good practice to propagate cancellation)
	ctx, cancel := context.WithTimeout(c.Request().Context(), 3*time.Second)
	defer cancel()

	httpReq, err := http.NewRequestWithContext(ctx, http.MethodGet, req.URL, nil)
	if err != nil {
		return c.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL format"})
	}

	// Set User-Agent to avoid being blocked by some servers
	httpReq.Header.Set("User-Agent", "Go-URL-Preview-Fetcher/1.0")

	// 3. Fetch the URL
	resp, err := client.Do(httpReq)
	if err != nil {
		// Distinguish between timeout and other errors
		if ctx.Err() == context.DeadlineExceeded {
			return c.JSON(http.StatusGatewayTimeout, map[string]string{"error": "Request timed out"})
		}
		return c.JSON(http.StatusBadGateway, map[string]string{"error": "Failed to fetch URL: " + err.Error()})
	}
	defer resp.Body.Close()

	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return c.JSON(http.StatusBadGateway, map[string]string{"error": "Remote server returned non-success status"})
	}

	// 4. Parse HTML
	doc, err := html.Parse(resp.Body)
	if err != nil {
		return c.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to parse HTML content"})
	}

	// 5. Extract Metadata
	title, description := extractMetadata(doc)

	// 6. Return Response
	return c.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// extractMetadata traverses the HTML node tree to find the title and meta description.
func extractMetadata(n *html.Node) (title, description string) {
	var crawler func(*html.Node)
	crawler = func(node *html.Node) {
		// Stop traversing if we found both (optimization)
		if title != "" && description != "" {
			return
		}

		if node.Type == html.ElementNode {
			// Extract Title
			if node.Data == "title" && title == "" {
				if node.FirstChild != nil {
					title = node.FirstChild.Data
				}
			}

			// Extract Meta Description
			if node.Data == "meta" && description == "" {
				var name, content string
				for _, attr := range node.Attr {
					k := strings.ToLower(attr.Key)
					if k == "name" {
						name = strings.ToLower(attr.Val)
					}
					if k == "content" {
						content = attr.Val
					}
				}
				if name == "description" {
					description = content
				}
			}
		}

		// Recursively traverse children
		for c := node.FirstChild; c != nil; c = c.NextSibling {
			crawler(c)
		}
	}

	crawler(n)
	return
}

