	// Use a shorter timeout for the fetch operation than the global request timeout
	requestCtx, cancel := context.WithTimeout(ctx.Request().Context(), 5*time.Second)
	defer cancel()

	// 4. SSRF Protection: Custom Transport
	// We must validate the IP address *after* DNS resolution but *before* connection
	// to prevent DNS rebinding attacks and access to internal networks.
	transport := &http.Transport{
		DialContext: func(ctx context.Context, network, addr string) (net.Conn, error) {
			host, port, err := net.SplitHostPort(addr)
			if err != nil {
				return nil, err
			}

			ips, err := net.LookupIP(host)
			if err != nil {
				return nil, err
			}

			for _, ip := range ips {
